"""Path helpers for Codex migration-family support tooling."""

from __future__ import annotations

import json
import os
from functools import lru_cache
from pathlib import Path


def find_repo_root(start: Path | None = None) -> Path:
    """Walk upward from ``start`` to find the example repository root."""
    p = (start or Path(__file__).resolve().parent).resolve()
    if p.is_file():
        p = p.parent

    while p != p.parent:
        git_sentinel = p / ".git"
        if git_sentinel.is_dir() or git_sentinel.is_file():
            return p
        if (p / "package.json").is_file():
            return p
        p = p.parent

    raise RuntimeError("Repository root not found")


def tracker_file_path(repo_root: Path | None = None) -> Path:
    """Return the live migration tracker JSON path."""
    root = repo_root or find_repo_root()
    return root / "migration-state.json"


def archived_tracker_file_path(repo_root: Path | None = None) -> Path:
    """Return the archived migration tracker JSON path."""
    root = repo_root or find_repo_root()
    return root / "migration-state.archived.json"


def default_user_codex_home() -> Path:
    """Return the user's active Codex home directory."""
    override = os.environ.get("CODEX_HOME")
    if override:
        return Path(override).expanduser()
    return Path.home() / ".codex"


def default_user_claude_home() -> Path:
    """Return the user's active Claude home directory."""
    override = os.environ.get("CLAUDE_HOME")
    if override:
        return Path(override).expanduser()
    return Path.home() / ".claude"


@lru_cache(maxsize=None)
def discover_plugin_skill_names(
    *,
    codex_home: Path | None = None,
    repo_root: Path | None = None,
) -> tuple[str, ...]:
    """Return namespaced skill ids exposed by installed Codex plugins.

    Plugin skill names are returned as ``<plugin-name>:<skill-name>`` to match
    how Claude-authored source skills often reference plugin-backed skills.
    """

    search_roots = []
    if codex_home is not None:
        search_roots.append(codex_home / "plugins")
    else:
        search_roots.append(default_user_codex_home() / "plugins")
    if repo_root is not None:
        search_roots.append(repo_root / ".agents" / "plugins")

    discovered: set[str] = set()
    for plugins_root in search_roots:
        if not plugins_root.exists():
            continue
        for manifest_path in sorted(plugins_root.rglob(".codex-plugin/plugin.json")):
            plugin_root = manifest_path.parent.parent
            try:
                payload = json.loads(manifest_path.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError):
                continue

            plugin_name = payload.get("name")
            if not isinstance(plugin_name, str) or not plugin_name.strip():
                plugin_name = plugin_root.name

            skills_rel = payload.get("skills")
            skill_root = plugin_root / skills_rel if isinstance(skills_rel, str) else plugin_root / "skills"
            if not skill_root.exists():
                fallback_skill_root = plugin_root / "skills"
                if not fallback_skill_root.exists():
                    continue
                skill_root = fallback_skill_root

            for skill_dir in sorted(path for path in skill_root.iterdir() if path.is_dir()):
                if (skill_dir / "SKILL.md").is_file():
                    discovered.add(f"{plugin_name}:{skill_dir.name}")

    return tuple(sorted(discovered))


@lru_cache(maxsize=None)
def discover_claude_plugin_skill_names(*, claude_home: Path | None = None) -> tuple[str, ...]:
    """Return namespaced skill ids exposed by installed Claude plugins.

    Claude plugin skill names are returned as ``<plugin-name>:<skill-name>`` to align
    with how Claude-authored skills commonly reference plugin-backed skills.
    """

    root = (claude_home or default_user_claude_home()).resolve() / "plugins"
    manifest_path = root / "installed_plugins.json"
    if not manifest_path.exists():
        return ()

    try:
        payload = json.loads(manifest_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return ()

    plugins = payload.get("installed_plugins")
    if not isinstance(plugins, list):
        plugins = payload.get("installedPlugins")
    if not isinstance(plugins, list):
        return ()

    discovered: set[str] = set()
    for plugin in plugins:
        if not isinstance(plugin, dict):
            continue
        slug = plugin.get("slug")
        if not isinstance(slug, str) or not slug.strip():
            continue
        plugin_dir = root / slug

        name = plugin.get("name")
        if not isinstance(name, str) or not name.strip():
            name = slug.split("@", 1)[0]

        skills_root = plugin_dir / "skills"
        if not skills_root.exists():
            continue
        for skill_dir in sorted(path for path in skills_root.iterdir() if path.is_dir()):
            if (skill_dir / "SKILL.md").is_file():
                discovered.add(f"{name}:{skill_dir.name}")

    return tuple(sorted(discovered))


def find_claude_plugin_skill_dir(
    skill_token: str,
    *,
    claude_home: Path | None = None,
) -> Path | None:
    """Resolve a namespaced Claude plugin skill token to its on-disk directory.

    Returns the directory containing ``SKILL.md`` for the referenced plugin skill, or
    ``None`` if it cannot be located.
    """

    if ":" not in skill_token:
        return None
    plugin_name, skill_name = (part.strip() for part in skill_token.split(":", 1))
    if not plugin_name or not skill_name:
        return None

    root = (claude_home or default_user_claude_home()).expanduser().resolve() / "plugins"
    manifest_path = root / "installed_plugins.json"
    if not manifest_path.exists():
        return None

    try:
        payload = json.loads(manifest_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return None

    plugins = payload.get("installed_plugins")
    if not isinstance(plugins, list):
        plugins = payload.get("installedPlugins")
    if not isinstance(plugins, list):
        return None

    wanted = plugin_name.lower()
    for plugin in plugins:
        if not isinstance(plugin, dict):
            continue
        slug = plugin.get("slug")
        if not isinstance(slug, str) or not slug.strip():
            continue
        plugin_dir = root / slug

        name = plugin.get("name")
        if not isinstance(name, str) or not name.strip():
            name = slug.split("@", 1)[0]

        normalized_name = name.strip().lower()
        normalized_slug = slug.split("@", 1)[0].strip().lower()
        if wanted not in {normalized_name, normalized_slug}:
            continue

        candidate = plugin_dir / "skills" / skill_name
        if (candidate / "SKILL.md").is_file():
            return candidate

    return None
